import { getUser } from 'wasp/server/auth'

export const getTasks = async (context: any) => {
  const user = await getUser(context)

  if (!user) {
    throw new Error('User not authenticated')
  }

  const tasks = await context.entities.Task.findMany({
    where: {
      userId: user.id
    },
    orderBy: {
      id: 'asc'
    }
  })

  return tasks
}

