import { useState } from 'react'
import { logout } from 'wasp/client/auth'
import { getTasks } from 'wasp/client/queries'
import { createTask, updateTask } from 'wasp/client/actions'
import { useQuery, useAction } from '@wasp/queries'
import './Main.css'

export function MainPage() {
  const [newTaskDescription, setNewTaskDescription] = useState('')
  const { data: tasks, isLoading, refetch } = useQuery(getTasks)
  const createTaskFn = useAction(createTask)
  const updateTaskFn = useAction(updateTask)

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newTaskDescription.trim()) return

    try {
      await createTaskFn(newTaskDescription)
      setNewTaskDescription('')
      refetch()
    } catch (error) {
      console.error('Failed to create task:', error)
    }
  }

  const handleToggleTask = async (taskId: number, currentIsDone: boolean) => {
    try {
      await updateTaskFn({ id: taskId, isDone: !currentIsDone })
      refetch()
    } catch (error) {
      console.error('Failed to update task:', error)
    }
  }

  const handleLogout = async () => {
    await logout()
  }

  if (isLoading) {
    return <div style={{ textAlign: 'center', marginTop: '50px' }}>Loading...</div>
  }

  return (
    <div className="container">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <h1 className="title">Todo List</h1>
        <button onClick={handleLogout} className="button button-outlined">
          Logout
        </button>
      </div>

      <form onSubmit={handleCreateTask} style={{ marginBottom: '30px' }}>
        <div style={{ display: 'flex', gap: '10px' }}>
          <input
            type="text"
            value={newTaskDescription}
            onChange={(e) => setNewTaskDescription(e.target.value)}
            placeholder="Add a new task..."
            style={{
              flex: 1,
              padding: '10px',
              border: '1px solid #ccc',
              borderRadius: '4px',
              fontSize: '16px'
            }}
          />
          <button type="submit" className="button button-filled">
            Add Task
          </button>
        </div>
      </form>

      <div style={{ marginTop: '30px' }}>
        {tasks && tasks.length > 0 ? (
          <ul style={{ listStyle: 'none', padding: 0 }}>
            {tasks.map((task) => (
              <li
                key={task.id}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  padding: '12px',
                  borderBottom: '1px solid #eee',
                  gap: '12px'
                }}
              >
                <input
                  type="checkbox"
                  checked={task.isDone}
                  onChange={() => handleToggleTask(task.id, task.isDone)}
                  style={{
                    width: '20px',
                    height: '20px',
                    cursor: 'pointer'
                  }}
                />
                <span
                  style={{
                    flex: 1,
                    textDecoration: task.isDone ? 'line-through' : 'none',
                    color: task.isDone ? '#888' : '#333',
                    fontSize: '16px'
                  }}
                >
                  {task.description}
                </span>
              </li>
            ))}
          </ul>
        ) : (
          <p style={{ textAlign: 'center', color: '#888', marginTop: '30px' }}>
            No tasks yet. Add one above!
          </p>
        )}
      </div>
    </div>
  )
}

