import { getUser } from 'wasp/server/auth'

export const createTask = async (description: string, context: any) => {
  const user = await getUser(context)

  if (!user) {
    throw new Error('User not authenticated')
  }

  const task = await context.entities.Task.create({
    data: {
      description,
      isDone: false,
      userId: user.id
    }
  })

  return task
}

export const updateTask = async ({ id, isDone }: { id: number; isDone: boolean }, context: any) => {
  const user = await getUser(context)

  if (!user) {
    throw new Error('User not authenticated')
  }

  const task = await context.entities.Task.findUnique({
    where: { id }
  })

  if (!task) {
    throw new Error('Task not found')
  }

  if (task.userId !== user.id) {
    throw new Error('Unauthorized')
  }

  const updatedTask = await context.entities.Task.update({
    where: { id },
    data: { isDone }
  })

  return updatedTask
}

